# Define the matrix A
A = np.array([[1, 0, 0],
              [2, 2, 0],
              [3, 3, 3]], dtype=float)

# Compute the true inverse for comparison
A_inv_true = np.linalg.inv(A)

print("Matrix A:")
print(A)
print("\nTrue Inverse (numpy):")
print(A_inv_true)

# ─── Newton-Schulz Iteration ───────────────────────────────────────────────
# X_{k+1} = X_k (2I - A X_k)
# Initialization: X_0 = alpha * A^T  where alpha = 1 / (||A||_1 * ||A||_inf)
# This guarantees convergence when ||I - A X_0|| < 1

norm_1   = np.linalg.norm(A, ord=1)
norm_inf = np.linalg.norm(A, ord=np.inf)
alpha    = 1.0 / (norm_1 * norm_inf)

X = alpha * A.T          # Initial guess
I = np.eye(A.shape[0])

errors          = []     # ||X_k - A^{-1}||_F
residuals       = []     # ||I - A X_k||_F
frobenius_norms = []     # ||X_k||_F

max_iter = 50
tol      = 1e-12

print("\nNewton-Schulz Iterations:")
print(f"{'Iter':>5}  {'||X_k - A_inv||_F':>20}  {'||I - A X_k||_F':>18}")
