for k in range(max_iter):
    err      = np.linalg.norm(X - A_inv_true, 'fro')
    residual = np.linalg.norm(I - A @ X, 'fro')
    frob     = np.linalg.norm(X, 'fro')

    errors.append(err)
    residuals.append(residual)
    frobenius_norms.append(frob)

    print(f"{k:>5}  {err:>20.6e}  {residual:>18.6e}")

    if err < tol:
        print(f"\nConverged at iteration {k}  (error < {tol})")
        break

    # Newton-Schulz update
    X = X @ (2 * I - A @ X)

X_ns = X   # Final approximation

print("\nNewton-Schulz Inverse:")
print(X_ns)
print(f"\nFinal error ||X - A^{{-1}}||_F = {errors[-1]:.6e}")

# ─── Plotting ──────────────────────────────────────────────────────────────
